import{_ as t,o as r,c as a,ae as e}from"./chunks/framework.BEE-8mnG.js";const c=JSON.parse('{"title":"Philosophy & Strategic Core","description":"","frontmatter":{},"headers":[],"relativePath":"philosophy.md","filePath":"philosophy.md"}'),i={name:"philosophy.md"};function l(s,o,n,h,g,p){return r(),a("div",null,[...o[0]||(o[0]=[e('<h1 id="philosophy-strategic-core" tabindex="-1">Philosophy &amp; Strategic Core <a class="header-anchor" href="#philosophy-strategic-core" aria-label="Permalink to &quot;Philosophy &amp; Strategic Core&quot;">​</a></h1><p><strong>&quot;수익률을 극대화하기 위해 만든 것이 아닙니다. 장기간 망가지지 않기 위해 기존의 모든 정석을 하나씩 버린 결과물입니다.&quot;</strong> - WeJump Labs</p><hr><h2 id="🏛️-1-전략의-기원-무엇을-버려야-살아남는가" tabindex="-1">🏛️ 1. 전략의 기원: 무엇을 버려야 살아남는가 <a class="header-anchor" href="#🏛️-1-전략의-기원-무엇을-버려야-살아남는가" aria-label="Permalink to &quot;🏛️ 1. 전략의 기원: 무엇을 버려야 살아남는가&quot;">​</a></h2><p>CBVR(Channel-Based Volatility Rebalancing)은 새로운 아이디어에서 출발한 전략이 아닙니다. 오히려 기존의 모든 정석을 실제로 사용해보고, 그 한계를 통과한 결과물입니다.</p><ul><li><strong>실패의 기록:</strong> 매수·매도로 모든 상황을 해결하려던 시도, 정교한 타이밍을 노리는 시스템 트레이딩, 그리고 상관관계 분산에 의존하는 자산배분 전략(60/40, 올웨더) 등이 시장 국면 전환 시 어떻게 붕괴(Strategy Decay)하는지를 목격했습니다.</li><li><strong>철학적 전환:</strong> &quot;어떻게 맞힐 것인가?(Prediction)&quot;라는 질문을 버리고, **&quot;무엇을 버려야 살아남는가?(Survival)&quot;**라는 질문에 답하기 시작했습니다.</li></ul><h2 id="🛡️-2-생존-survival-과-에르고드성-ergodicity" tabindex="-1">🛡️ 2. 생존(Survival)과 에르고드성 (Ergodicity) <a class="header-anchor" href="#🛡️-2-생존-survival-과-에르고드성-ergodicity" aria-label="Permalink to &quot;🛡️ 2. 생존(Survival)과 에르고드성 (Ergodicity)&quot;">​</a></h2><p>수익보다 중요한 것은 **&#39;시장에서 퇴출당하지 않는 것&#39;**입니다. 자산을 섞는다고 자산 고유의 위험 구조가 바뀌지는 않습니다.</p><ul><li><strong>섞지 말고, 가공하라:</strong> CBVR은 자산 간 상관관계의 안정성이라는 환상을 버립니다. 대신 주가지수라는 기초 자산을 **&#39;엔진&#39;**에 통과시켜 위험 구조를 직접 가공합니다.</li><li><strong>예측의 폐기:</strong> 매수·매도의 정확성을 경쟁하지 않습니다. 추세를 맞히려 하지 않으며, 종목을 고르지 않습니다. 오직 시장의 위치와 속도에 따라 <strong>노출도(Beta)를 조절</strong>할 뿐입니다.</li></ul><h2 id="⚙️-3-불변의-원리-수렴과-발산의-구조" tabindex="-1">⚙️ 3. 불변의 원리: 수렴과 발산의 구조 <a class="header-anchor" href="#⚙️-3-불변의-원리-수렴과-발산의-구조" aria-label="Permalink to &quot;⚙️ 3. 불변의 원리: 수렴과 발산의 구조&quot;">​</a></h2><p>시장은 유혹하고, 사람들은 그 뒤를 쫓습니다. 하지만 CBVR은 차라리 눈을 감고 변하지 않는 물리적 원리에 집중합니다.</p><ol><li><strong>위치(Level):</strong> 주가는 언제나 평균을 기준으로 멀어졌다가 다시 가까워지는 수렴과 발산의 구조를 반복합니다.</li><li><strong>기울기(Slope):</strong> 같은 채널 하단이라도 횡보 국면과 강한 하락 추세는 전혀 다른 위험을 가집니다.</li></ol><p>CBVR은 이 단순한 두 가지 변수만을 상수(Constants)로 삼아 시스템을 운용합니다. 복잡한 전략은 백테스트에서 화려하지만 실전에서 붕괴하며, <strong>변하지 않는 원리로 압축된 단순한 전략</strong>만이 실전에서 살아남습니다.</p><h2 id="🔄-4-전략의-진화-evolution-registry" tabindex="-1">🔄 4. 전략의 진화 (Evolution Registry) <a class="header-anchor" href="#🔄-4-전략의-진화-evolution-registry" aria-label="Permalink to &quot;🔄 4. 전략의 진화 (Evolution Registry)&quot;">​</a></h2><p>CBVR은 고정된 알고리즘이 아니라, 매 시장 국면(Regime)의 변화를 학습하며 &#39;자본의 유효성&#39;을 극대화해 나가는 진화형 프레임워크입니다.</p><ul><li><strong>v1.0:</strong> 신호 센싱을 통한 시장 국면 판별 (Alpha Signal).</li><li><strong>v2.3:</strong> 선물 복제 + 3-Bucket 구조를 통한 <strong>자본 효율성 및 실물 복리(Realized Compounding) 완성.</strong></li></ul><hr><blockquote><p><strong>Key Insight:</strong> &quot;성공적인 투자는 영리한 예측의 결과가 아니라, <strong>실수한 적 없는 가혹한 관리</strong>의 결과입니다.&quot; 🐯🐾</p></blockquote>',18)])])}const d=t(i,[["render",l]]);export{c as __pageData,d as default};
